struct SafeDivide {
    numerator: i32,
    denominator: i32,
}

impl Drop for SafeDivide {
    fn drop(&mut self) {
        println!("Dropping SafeDivide");
        if self.denominator != 0 {
            let _ = self.numerator / self.denominator;
        } else {
            eprintln!("Denominator is zero, not dividing");
        }
    }
}

